package com.taskmind.backend.task.application; import com.taskmind.backend.auth.AuthenticatedUser; import com.taskmind.backend.task.domain.model.*; import com.taskmind.backend.task.domain.repository.*; import java.time.Instant; import java.util.*; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional;
@Service public class TaskLinkApplicationService{private final TaskRepository tasks;private final TaskLinkRepository links;public TaskLinkApplicationService(TaskRepository t,TaskLinkRepository l){tasks=t;links=l;}@Transactional public TaskLink create(AuthenticatedUser u,UUID source,UUID target,TaskLinkType type){var s=authorized(u,source);var t=authorized(u,target);if(s.projectId()==null||!s.projectId().equals(t.projectId()))throw new IllegalArgumentException("Linked tasks must belong to the same project");return links.save(new TaskLink(UUID.randomUUID(),null,source,target,type,u.userId(),Instant.now()));}public List<TaskLink> list(AuthenticatedUser u,UUID id){authorized(u,id);return links.findForTask(id);}@Transactional public void delete(AuthenticatedUser u,UUID id){var l=links.findById(id).orElseThrow();authorized(u,l.sourceTaskId());links.deleteById(id);}private Task authorized(AuthenticatedUser u,UUID id){var t=tasks.findById(id).orElseThrow();if(!u.isPrivileged()&&!u.userId().equals(t.userId()))throw new IllegalArgumentException("Access denied");return t;}}
